function isPerfectSquare(num) {
    if (num < 2) return true;
    let left = 2, right = Math.floor(num / 2), mid, square;
    while (left <= right) {
        mid = left + Math.floor((right - left) / 2);
        square = mid * mid;
        if (square === num) return true;
        if (square > num) right = mid - 1;
        else left = mid + 1;
    }
    return false;
}
```

